import React, { useState, useRef } from 'react';
import { classifyWaste, IMPACT, OBJECT_IMPACT } from '../services/api';
import { addRecord, isDuplicate, claimDailyBonus, ECO_POINTS, calcGreenCredits } from '../services/store';
import ResultCard from '../components/ResultCard';
import ImpactPanel from '../components/ImpactPanel';
import useScrollReveal from '../hooks/useScrollReveal';
import './Home.css';

export default function Home() {
  const [preview, setPreview]   = useState(null);
  const [file, setFile]         = useState(null);
  const [loading, setLoading]   = useState(false);
  const [result, setResult]     = useState(null);
  const [error, setError]       = useState('');
  const [toast, setToast]       = useState(null);
  const inputRef = useRef();

  function showToast(msg, type = 'success') {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  }

  function handleFileChange(e) {
    const f = e.target.files[0];
    if (!f) return;
    if (!f.type.startsWith('image/')) { showToast('Please select an image file', 'error'); return; }
    setFile(f);
    setResult(null);
    setError('');
    const reader = new FileReader();
    reader.onload = ev => setPreview(ev.target.result);
    reader.readAsDataURL(f);
  }

  async function handleSubmit(e) {
    e.preventDefault();
    if (!file) { showToast('Select or capture an image first', 'error'); return; }
    const duplicate = isDuplicate(file);
    setLoading(true); setError(''); setResult(null);
    try {
      const data = await classifyWaste(file);
      const category  = data.prediction;
      const impact    = IMPACT[category];
      if (!impact) throw new Error('Unknown category: ' + category);
      // Merge per-object real-world numbers over the category defaults
      const objectKey = (data.object || '').toLowerCase();
      const objectMetrics = OBJECT_IMPACT[objectKey] || {};
      const co2Saved = objectMetrics.co2Saved !== undefined ? objectMetrics.co2Saved : (impact.co2Saved || 0);
      const objectDetected = data.object || null;

      // If duplicate, still show the classification but don't award points or store a record.
      const earned = duplicate ? 0 : (ECO_POINTS[category] || 5);
      const gotBonus = duplicate ? false : claimDailyBonus();
      const totalPts = earned + (gotBonus ? ECO_POINTS.DailyBonus : 0);
      const greenCredits = duplicate ? 0 : calcGreenCredits(co2Saved, category);
      const record = duplicate ? null : addRecord(category, objectMetrics.guidance || impact.guidance, file, co2Saved, objectDetected);

      setResult({
        category,
        impact: {
          ...impact,
          ...objectMetrics,          // override co2Saved/energySaved/landfillSaved/treeDays with per-material values
          detectedObject: data.object || data.detectedObject || null,
          confidence: data.confidence != null ? Number(data.confidence) : null,
        },
        record,
        ecoPoints: earned,
        bonusPoints: gotBonus ? ECO_POINTS.DailyBonus : 0,
        greenCredits,
        co2Saved,
      });

      if (duplicate) {
        showToast('Duplicate image detected — classified, but no eco-points earned.', 'error');
      } else {
        showToast('+' + totalPts + ' eco-points earned! 🌱');
      }
    } catch (err) {
      setError(err.message || 'Something went wrong. Is the server running?');
      showToast(err.message || 'Error', 'error');
    } finally { setLoading(false); }
  }

  function handleReset() {
    setPreview(null); setFile(null); setResult(null); setError('');
    if (inputRef.current) inputRef.current.value = '';
  }

  /* Ring circumference for r=104 → 2π×104 ≈ 653 */
  const CIRC = 653;
  const confidence = result?.impact?.confidence ?? null;
  const ringOffset = confidence !== null ? CIRC * (1 - confidence) : 0;

  const CAT_ICON = {
    Recyclable: '♻️', Hazardous: '☢️', Biodegradable: '🌿', default: '🗑️',
  };
  const catIcon = result ? (CAT_ICON[result.category] || CAT_ICON.default) : null;

  useScrollReveal([result, preview]);

  return (
    <div className="page-content home-page">

      {/* ── Top Bar ── */}
      <header className="home-topbar">
        <div>
          <p className="topbar-greeting">Good day</p>
          <h1 className="topbar-title">VERDANT<span style={{color:'var(--brand-teal)'}}>.</span></h1>
          <p className="topbar-sub">AI Waste Intelligence</p>
        </div>
        <div className="topbar-avatar">🌿</div>
      </header>

      {/* ── Ring Hero ── */}
      <section className="ring-hero" data-reveal="scale">
        <div className="scan-ring-wrap">
          {/* Overlaid file input covers entire ring */}
          {!loading && !result && (
            <input
              type="file" accept="image/*"
              ref={inputRef}
              onChange={handleFileChange}
              title="Tap to scan waste"
            />
          )}

          {/* SVG Ring */}
          <svg className="scan-ring-svg" viewBox="0 0 240 240">
            <circle className="ring-track" cx="120" cy="120" r="104" />
            <circle
              className={`ring-fill${loading ? ' scanning' : ''}`}
              cx="120" cy="120" r="104"
              strokeDasharray={CIRC}
              strokeDashoffset={loading ? 400 : ringOffset}
            />
          </svg>

          {/* Inner circle content */}
          <div className="ring-inner">
            {/* Idle – no image yet */}
            {!preview && !loading && !result && (
              <>
                <span className="ring-idle-icon">📷</span>
                <span className="ring-idle-label">Tap ring to scan waste</span>
              </>
            )}

            {/* Image selected but not submitted */}
            {preview && !loading && !result && (
              <>
                <img src={preview} alt="preview" className="ring-inner-img" />
              </>
            )}

            {/* Scanning animation */}
            {loading && (
              <div className="ring-scan-overlay">
                <div className="ring-scan-line" />
                <span className="ring-scan-text">ANALYSING…</span>
              </div>
            )}

            {/* Result shown inside ring */}
            {result && (
              <>
                {preview && <img src={preview} alt="scanned" className="ring-inner-img" />}
                <div className="ring-scan-overlay" style={{background:'rgba(8,15,11,.55)'}}>
                  <span className="ring-result-icon">{catIcon}</span>
                  <span className="ring-result-cat">{result.category}</span>
                </div>
              </>
            )}
          </div>
        </div>

        {/* Status text below ring */}
        <div className="ring-status">
          {!preview && !loading && !result && (
            <>
              <div className="ring-status-main">Ready to Scan</div>
              <div className="ring-status-sub">Tap the ring · JPG · PNG · WEBP</div>
            </>
          )}
          {preview && !loading && !result && (
            <>
              <div className="ring-status-main">Image Selected</div>
              <div className="ring-status-sub">Hit Classify to analyse</div>
            </>
          )}
          {loading && (
            <>
              <div className="ring-status-main" style={{color:'var(--brand-teal)'}}>Scanning…</div>
              <div className="ring-status-sub">AI model running</div>
            </>
          )}
          {result && (
            <>
              <div className="ring-status-main" style={{color:'var(--brand-teal)'}}>
                {confidence !== null ? `${(confidence * 100).toFixed(0)}% Confidence` : 'Classified'}
              </div>
              <div className="ring-status-sub">{result.impact?.detectedObject || result.category}</div>
            </>
          )}
        </div>
      </section>

      {/* ── Error ── */}
      {error && <div className="error-strip">⚠ {error}</div>}

      {/* ── Stat Cards (live after result) ── */}
      <div className="home-stats-grid" data-reveal data-reveal-delay="100">
        <div className={`stat-card${result ? ' accent' : ''}`}>
          <div className="stat-card-top">
            <span className="stat-card-icon">🌫️</span>
            <span className="stat-card-label">CO₂ Prevented</span>
          </div>
          <div>
            <span className="stat-card-value">{result ? result.co2Saved.toFixed(2) : '–'}</span>
            <span className="stat-card-unit">kg</span>
          </div>
          {result && (
            <div className="stat-bar">
              <div className="stat-bar-fill" style={{width: `${Math.min(100, result.co2Saved * 100)}%`}} />
            </div>
          )}
          <div className="stat-card-sub">{result ? 'This item' : 'Scan to see impact'}</div>
        </div>

        <div className={`stat-card${result ? ' accent' : ''}`}>
          <div className="stat-card-top">
            <span className="stat-card-icon">🟢</span>
            <span className="stat-card-label">Green Credits</span>
          </div>
          <div>
            <span className="stat-card-value">{result ? result.greenCredits : '–'}</span>
            <span className="stat-card-unit">pts</span>
          </div>
          {result && (
            <div className="stat-bar">
              <div className="stat-bar-fill" style={{width: `${Math.min(100, result.greenCredits * 5)}%`}} />
            </div>
          )}
          <div className="stat-card-sub">{result ? 'Earned now' : 'Awaiting scan'}</div>
        </div>

        <div className="stat-card">
          <div className="stat-card-top">
            <span className="stat-card-icon">♻️</span>
            <span className="stat-card-label">Category</span>
          </div>
          <div style={{fontFamily:'var(--font-display)',fontSize:'1.05rem',fontWeight:800,color:'var(--text-primary)',lineHeight:1}}>
            {result ? result.category : '—'}
          </div>
          <div className="stat-card-sub">{result ? (result.impact?.detectedObject || 'AI classified') : 'Pending'}</div>
        </div>

        <div className="stat-card">
          <div className="stat-card-top">
            <span className="stat-card-icon">🌳</span>
            <span className="stat-card-label">Tree Equiv.</span>
          </div>
          <div>
            <span className="stat-card-value">{result ? (result.impact?.treeDays ?? '–') : '–'}</span>
            <span className="stat-card-unit">days</span>
          </div>
          <div className="stat-card-sub">{result ? 'CO₂ absorbed' : 'Awaiting scan'}</div>
        </div>
      </div>

      {/* ── Action Buttons ── */}
      <div className="home-actions" data-reveal data-reveal-delay="200">
        {!preview && !result && (
          <>
            <label className="action-btn action-secondary" htmlFor="camera-input">
              📷 Camera
            </label>
            <input id="camera-input" type="file" accept="image/*" capture="environment" hidden onChange={handleFileChange} />

            <label className="action-btn action-ghost" htmlFor="gallery-input">
              🖼 Upload
            </label>
            <input id="gallery-input" type="file" accept="image/*" hidden onChange={handleFileChange} />
          </>
        )}

        {preview && !result && !loading && (
          <button className="action-btn action-primary action-full" onClick={handleSubmit}>
            🔍 Classify This Item
          </button>
        )}

        {result && (
          <button className="action-btn action-ghost action-full" onClick={handleReset}>
            ↩ Scan Another Item
          </button>
        )}
      </div>

      {/* ── Result Details (ResultCard + ImpactPanel) ── */}
      {result && (
        <div style={{ animation: 'fadeUp .4s ease both', paddingBottom: '8px' }}>
          <ResultCard
            category={result.category}
            impact={result.impact}
            ecoPoints={result.ecoPoints}
            bonusPoints={result.bonusPoints}
            greenCredits={result.greenCredits}
            co2Saved={result.co2Saved}
          />
          <ImpactPanel impact={result.impact} single />
        </div>
      )}

      {/* ── How It Works (idle only) ── */}
      {!preview && !result && (
        <section className="how-section" data-reveal data-reveal-delay="150">
          <div className="section-label">HOW IT WORKS</div>
          <div className="how-steps">
            {[
              { n: '01', title: 'Tap the Ring', desc: 'Select a photo from gallery or take one with camera.' },
              { n: '02', title: 'AI Classifies', desc: 'Roboflow model identifies waste type in milliseconds.' },
              { n: '03', title: 'Earn & Act', desc: 'Get bin guidance, CO₂ data and Green Credits.' },
            ].map(s => (
              <div className="how-step" key={s.n}>
                <span className="step-num">{s.n}</span>
                <div>
                  <p className="step-title">{s.title}</p>
                  <p className="step-desc">{s.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {toast && <div className={`toast ${toast.type}`}>{toast.msg}</div>}
    </div>
  );
}
